            Tags = """["leads","sales","reference"]""",
            ContentJson = """{"title":"Leads Field Reference","groups":[{"heading":"Lead Form Fields","items":[{"label":"Company Name (required)","value":"Text input, identifies the prospect company. Must not be empty. This becomes the Customer name if the lead is converted. data-testid: lead-company-name"},{"label":"Contact Name","value":"Text input, optional. The person at the company you're working with. If provided, a Contact record is created when the lead is converted (first/last name split on space). data-testid: lead-contact-name"},{"label":"Email","value":"Text input, optional. Validated as email format (must contain @). Carried over to the Customer and Contact records on conversion. data-testid: lead-email"},{"label":"Phone","value":"Text input, optional. Phone number for the contact. Carried over to Customer and Contact on conversion. data-testid: lead-phone"},{"label":"Source","value":"Dropdown, optional. How the lead found you. Options are loaded from Reference Data (group: lead_source) — configurable in Admin. Examples: Referral, Website, Trade Show, Cold Call. Includes a '-- None --' option. data-testid: lead-source"},{"label":"Follow-Up Date","value":"Date picker, optional. When you should next follow up with this lead. Displays in red (overdue) in the table and detail view when the date has passed. data-testid: lead-follow-up"},{"label":"Notes","value":"Textarea, optional. Free-form notes about the lead, opportunity details, conversation history, or requirements. data-testid: lead-notes"}]},{"heading":"Lead Statuses","items":[{"label":"New (primary/blue chip)","value":"Default status for new leads. Indicates the lead has not been contacted yet. CSS class: chip--primary."},{"label":"Contacted (info/teal chip)","value":"You have reached out to the prospect. They are aware of your company and offerings. CSS class: chip--info."},{"label":"Quoting (warning/yellow chip)","value":"A quote or estimate is being prepared or has been sent to the prospect. CSS class: chip--warning."},{"label":"Converted (success/green chip)","value":"Terminal status. The lead has been converted to a Customer record. A green check badge appears in the detail view. Cannot be set manually — only through the Convert action. CSS class: chip--success."},{"label":"Lost (muted/gray chip)","value":"Terminal status. The opportunity did not result in a customer. A lost reason can be recorded. Can be reopened back to New. CSS class: chip--muted."}]},{"heading":"Table Columns","items":[{"label":"Company","value":"Sortable. The company name, displayed in bold/emphasized text."},{"label":"Contact","value":"Sortable. Contact person name. Shows em-dash (—) when empty."},{"label":"Source","value":"Sortable. Lead source from Reference Data. Shows em-dash (—) when empty."},{"label":"Status","value":"Sortable, filterable (enum filter). Color-coded chip: New (blue), Contacted (teal), Quoting (yellow), Converted (green), Lost (gray)."},{"label":"Follow-Up","value":"Sortable, date type. Shows the follow-up date in MM/dd/yyyy format. Displays in red when overdue. Shows em-dash (—) when not set."},{"label":"Created","value":"Sortable, date type. Date the lead was created, in MM/dd/yyyy format."}]},{"heading":"Buttons and Actions","items":[{"label":"New Lead (primary button, header)","value":"Opens the create lead dialog. data-testid: new-lead-btn"},{"label":"Table View toggle (icon button)","value":"Switches to sortable data table view. Icon: view_list. Persisted to localStorage."},{"label":"Pipeline View toggle (icon button)","value":"Switches to kanban-style pipeline board. Icon: view_column. Persisted to localStorage."},{"label":"Save / Create Lead (dialog footer)","value":"Creates or updates the lead. Disabled when form is invalid or save is in progress. Shows validation popover on hover when disabled. data-testid: lead-save-btn"},{"label":"Cancel (dialog footer)","value":"Closes the dialog without saving."},{"label":"Edit (detail dialog icon button)","value":"Opens the edit dialog pre-filled with the lead's current values. Icon: edit."},{"label":"Close (detail dialog icon button)","value":"Closes the detail dialog. Icon: close."},{"label":"Status buttons (detail panel)","value":"Quick-action buttons to change status to New, Contacted, Quoting, or Lost directly from the detail panel. Hidden when lead is Converted or Lost. data-testid: lead-status-btn-{status}"},{"label":"Convert to Customer (detail panel)","value":"Single one-click action. Creates a Customer record from the lead data, marks the lead Converted, and navigates to the new customer's page — in one server transaction, no confirmation dialog. Only available when status is not Converted or Lost. Icon: person_add. data-testid: lead-convert-btn"},{"label":"Conversion does not create a job","value":"There is no separate 'Convert + Create Job' button. Conversion only creates the Customer; Jobs are produced later from the customer's quotes and Sales Orders. Credit, tax, and address details are entered on the customer page after conversion."},{"label":"Reopen Lead (detail panel)","value":"Resets a Lost lead back to New status. Only visible when status is Lost. Icon: replay."},{"label":"Confirm Lost (lost reason dialog)","value":"Confirms marking the lead as Lost with the optional reason."},{"label":"Row click","value":"Opens the lead detail dialog showing all fields, status actions, convert options, and activity log."},{"label":"Pipeline card drag","value":"Drag a card between pipeline columns to change status. Dropping on Lost opens the lost reason dialog."}]},{"heading":"Validation Rules","items":[{"label":"Company Name","value":"Required. Cannot be empty."},{"label":"Email","value":"Optional, but must be valid email format if provided (Validators.email)."},{"label":"All other fields","value":"Optional. No additional format restrictions."},{"label":"Submit button popover","value":"When form is invalid, hovering over Save shows a validation popover listing which fields need attention (e.g., 'Company Name is required')."},{"label":"Conversion guard","value":"Cannot convert a lead that is already Converted or Lost (server returns 400/InvalidOperationException). Lost leads must be reopened first."}]},{"heading":"Detail Dialog Sections","items":[{"label":"Header","value":"Company name (bold), contact name (subtitle), edit and close icon buttons."},{"label":"Info Grid","value":"Status chip, email, phone, source, follow-up date (red if overdue), lost reason (if Lost). Empty fields are hidden."},{"label":"Notes Section","value":"Displays lead notes as a paragraph. Hidden when notes are empty."},{"label":"Status Actions","value":"Row of status buttons for quick status changes. Hidden when Converted or Lost."},{"label":"Convert Actions","value":"A single Convert to Customer button (one-click conversion). Hidden when Converted or Lost."},{"label":"Converted Info","value":"Green check badge with confirmation text. Only shown when status is Converted."},{"label":"Reopen Action","value":"Reopen Lead button. Only shown when status is Lost."},{"label":"Activity Timeline","value":"Chronological activity log for the lead (EntityActivitySectionComponent). Shows status changes, edits, notes, and conversion events."}]},{"heading":"Pipeline View Details","items":[{"label":"Columns","value":"Five columns: New, Contacted, Quoting, Converted, Lost. Converted and Lost columns have muted styling."},{"label":"Column header","value":"Status name + count badge (chip--muted)."},{"label":"Card content","value":"Company name (bold), contact name with avatar initials, source with label icon, follow-up date with event icon (red if overdue)."},{"label":"Empty column","value":"Shows inbox icon with 'No leads' text."},{"label":"Drag-and-drop","value":"CDK drag-drop. Cards can be dragged between any columns. Dropping on Lost triggers the lost reason dialog. Connected drop lists allow cross-column movement."}]}]}"""
