            AppRoutes = """["/leads/intake"]""",
            Tags = """["leads","intake","import","walkthrough"]""",
            ContentJson = """{"appRoute":"/leads/intake","startButtonLabel":"Tour Bulk Intake","steps":[{"element":".intake__step:nth-of-type(1)","popover":{"title":"Step 1 — Pick the Strategy","description":"Choose how this batch was sourced: Cold Call, Cold Email, Trade Show Follow-up, Webinar Attendee, Purchased List, or Manual Entry. The strategy drives which fields are required and which suppression channel is checked — cold-call needs phone, cold-email needs email. Optionally add a Campaign tag (e.g. IMTS-2026) to group the batch for reporting.","side":"bottom"}},{"element":".intake__columns-help","popover":{"title":"Expected CSV Columns","description":"Only companyName is required; contactName, email, phone, source, and notes are optional. Column matching is case-insensitive and common aliases are accepted (company → companyName, tel → phone, etc.). Expand this reference any time you're unsure of the format.","side":"top"}},{"element":".intake__upload-button","popover":{"title":"Upload a CSV File","description":"Click here to choose a .csv file from your computer. The header row is required and must name the columns. As soon as the file is read, its rows are parsed and listed below.","side":"bottom"}},{"element":".intake__upload + app-textarea","popover":{"title":"Or Paste Rows","description":"Instead of a file, you can paste comma- or tab-separated rows directly — handy for a quick list copied from a spreadsheet. The first line must be the header row.","side":"top"}},{"element":"[data-testid='intake-parse-paste']","popover":{"title":"Parse Pasted Rows","description":"After pasting, click Parse pasted rows to read them into the preview table. Parse errors (malformed rows) are listed so you can fix the source data.","side":"top"}},{"element":"[data-testid='intake-preview-btn']","popover":{"title":"Run the Dedup Preview","description":"Once rows are parsed, run the preview. The server checks every row against existing leads, existing customers, suppressed/opted-out contacts, active cooldowns, and duplicates within the batch — then labels each row Will create, Duplicate, Opted out, In cooldown, or Missing field. No leads are created yet.","side":"top"}},{"element":"[data-testid='intake-commit-btn']","popover":{"title":"Commit the Valid Rows","description":"Review the per-row status table, then commit. Only rows labeled \"Will create\" are inserted — duplicates, opt-outs, and cooldowns are skipped automatically. A summary shows how many were created vs skipped, and you're returned to the Leads list.","side":"top"}}]}"""
